package main

import (
	"flag"
	"fmt"
	"log"
	"os"
	"path/filepath"
	"strings"

	"github.com/google/brotli/go/cbrotli"
)

var (
	quality      = flag.Int("quality", 11, "compression quality")
	windowSize   = flag.Int("window", 0, "window size")
	blockSize    = flag.Int("block", 0, "maximum block size")
	mode         = flag.String("mode", "text", "compression mode (text or font)")
	inputFile    = flag.String("i", "", "input file path")
	outputFile   = flag.String("o", "", "output file path")
	notNParallel = flag.Int("jobs", 1, "number of parallel jobs")
)

func main() {
	flag.Parse()

	if *inputFile == "" || *outputFile == "" {
		flag.Usage()
		os.Exit(1)
	}

	input, err := os.Open(*inputFile)
	if err != nil {
		log.Fatal(err)
	}
	defer input.Close()

	output, err := os.Create(*outputFile)
	if err != nil {
		log.Fatal(err)
	}
	defer output.Close()

	var modeVal cbrotli.Mode
	switch *mode {
	case "text":
		modeVal = cbrotli.Text
	case "font":
		modeVal = cbrotli.Font
	default:
		modeVal = cbrotli.Text
	}

	enc := cbrotli.NewEncoder(output, &cbrotli.EncoderOptions{
		Quality:      *quality,
		WindowSize:   *windowSize,
		BlockSize:    *blockSize,
		Mode:         modeVal,
		ParallelJobs: *notNParallel,
	})

	buf := make([]byte, 32*1024)
	for {
		n, err := input.Read(buf)
		if n > 0 {
			if _, err := enc.Write(buf[:n]); err != nil {
				log.Fatal(err)
			}
		}
		if err != nil {
			break
		}
	}
	if err := enc.Close(); err != nil {
		log.Fatal(err)
	}

	fmt.Printf("Input size: %d\n", getFileSize(*inputFile))
	fmt.Printf("Output size: %d\n", getFileSize(*outputFile))
}

func getFileSize(path string) int64 {
	path = strings.Replace(path, "\\", "/", -1)
	f, err := os.Open(path)
	if err != nil {
		return 0
	}
	defer f.Close()
	fi, err := f.Stat()
	if err != nil {
		return 0
	}
	return fi.Size()
}
